pattern.example:
stage('PR Review') {
    steps {
        script {
            catchError(buildResult: 'UNSTABLE', stageResult: 'FAILURE') {
                sh '''
                    git config --global --add safe.directory "$WORKSPACE"
                    git diff origin/main...HEAD > git-diff.txt || : > git-diff.txt
                '''

                def analysis = askBob(
                    "Read git-diff.txt and tell me what changed in this PR.",
                    'pipeline-git-diff-overview'
                )

                echo analysis
                writeFile file: 'bob-pr-review.md', text: analysis
            }
        }
    }
    post {
        always {
            archiveArtifacts artifacts: 'bob-pr-review.md', allowEmptyArchive: true
        }
    }
}

stage('Bob Test Analysis') {
    steps {
        script {
            catchError(buildResult: 'UNSTABLE', stageResult: 'FAILURE') {
                def reports = sh(
                    script: "find order-service/target/surefire-reports -name '*.txt' -exec cat {} +",
                    returnStdout: true
                ).trim()

                def analysis = askBob(
                    "Analyze these test failures:\n${reports}",
                    'pipeline-test-failure-analyzer'
                )

                echo analysis
                writeFile file: 'bob-test-analysis.md', text: analysis
            }
        }
    }
    post {
        always {
            archiveArtifacts artifacts: 'bob-test-analysis.md', allowEmptyArchive: true
        }
    }
}

// git-diff falls back to empty file on diff failure (e.g., on a build of main)
sh '''
    git config --global --add safe.directory "$WORKSPACE"
    git diff origin/main...HEAD > git-diff.txt || : > git-diff.txt
'''

// Test reports may not exist if the test stage was skipped
def reports = ''
if (fileExists('order-service/target/surefire-reports')) {
    reports = sh(
        script: "find order-service/target/surefire-reports -name '*.txt' -exec cat {} + || true",
        returnStdout: true
    ).trim()
}

def analysis = askBob(
    "Analyze these test failures (may be empty if tests didn't run):\n${reports}",
    'pipeline-test-failure-analyzer'
)

stage('Unit Tests') {
    steps {
        catchError(buildResult: 'UNSTABLE', stageResult: 'UNSTABLE') {
            sh "mvn -f order-service/pom.xml test"
        }
    }
}

// Always runs — analyzes whatever surefire wrote, success or failure
stage('Bob Test Analysis') {
    steps {
        script {
            catchError(buildResult: 'UNSTABLE', stageResult: 'FAILURE') {
                // ... read surefire reports, askBob ...
            }
        }
    }
}

stage('PR Review') {
    options {
        timeout(time: 5, unit: 'MINUTES')
    }
    steps {
        // ...
    }
}
